package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetCommentMarker_whenNull() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertNull(format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_whenSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertEquals(Character.valueOf('#'), format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_withDifferentCharacter() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('!');
        assertEquals(Character.valueOf('!'), format.getCommentMarker());
    }
}
